+	userConfig := `
+[[ensembles]]
+name = "project-diagnosis"
+display_name = "User Override"
+description = "user override"
+modes = [{id = "deductive"}, {id = "abductive"}]
+
+[[ensembles]]
+name = "custom-user"
+display_name = "Custom User"
+description = "user custom"
+modes = [{id = "deductive"}, {id = "abductive"}]
