+
+	userPreset := findPreset(t, presets, "custom-user")
+	if userPreset.Source != "user" {
+		t.Fatalf("expected user preset source, got %q", userPreset.Source)
+	}
+
+	projectPreset := findPreset(t, presets, "custom-project")
